function minCost(startAt, moveCost, pushCost, targetSeconds) {
    let min_cost = Infinity;

    for (let i = 0; i <= 99; i++) {
        for (let j = 0; j <= 99; j++) {
            if (i * 60 + j === targetSeconds) {
                let minute_move_cost = Math.abs(i - startAt) * moveCost;
                let second_move_cost = Math.abs(j - i) * moveCost;
                let total_push_cost = (j > 0 ? 2 : 0) + (j / 10 !== 0 ? 1 : 0) + (i / 10 !== 0 ? 1 : 0);

                min_cost = Math.min(min_cost, minute_move_cost + second_move_cost + total_push_cost * pushCost);
            }
        }
    }
    return min_cost;
}
```

    1. Initialize `min_cost` to a large value.
2. Iterate over all possible combinations of minute digits (i) and second digits (j) in the range of [0, 99].
3. Check if the current combination (`i * 60 + j`) matches the target seconds. If it does:
   a. Calculate and store the move cost for minute and second digits.
   b. Calculate and store the push cost for the current combination.
   c. Update `min_cost` with the minimum value between the current `min_cost` and the sum of move cost and push cost.
4. After iterating through all possible combinations, return the `min_cost`.

